record_types.code:
type Stat_Info is record
   Device  : Uint_64;
   Inode   : Uint_64;
   Mode    : File_Mode;
   Nlink   : Uint_64;
   Uid     : Uint_32;
   Gid     : Uint_32;
   Rdev    : Uint_64;
   Size    : Sint_64;
   Blksize : Sint_64;
   Blocks  : Sint_64;
   Atime   : Sint_64;
   Mtime   : Sint_64;
   Ctime   : Sint_64;
end record;

type Statvfs_Info is record
   Bsize    : Uint_64;
   Frsize   : Uint_64;
   Blocks   : Uint_64;
   Bfree    : Uint_64;
   Bavail   : Uint_64;
   Files    : Uint_64;
   Ffree    : Uint_64;
   FAvail   : Uint_64;
   Flags    : Uint_64;
   Namemax  : Uint_64;
   Pathmax  : Uint_64;
end record;
